+export interface DurationObservation {
+  duration: number
+  recordedAt: number
+}
+
+export function smoothDurations(observations: DurationObservation[], method: 'latest' | 'average' | 'p95' | 'median'): number {
+  if (!observations.length) return 0
+  if (method === 'latest') {
+    return observations.reduce((latest, value) => value.recordedAt > latest.recordedAt ? value : latest).duration
+  }
+  const durations = observations.map(value => value.duration).sort((a, b) => a - b)
+  if (method === 'average') return Math.round(durations.reduce((sum, value) => sum + value, 0) / durations.length)
+  if (method === 'p95') return durations[Math.ceil(0.95 * durations.length) - 1]
+  const middle = Math.floor(durations.length / 2)
+  return durations.length % 2 ? durations[middle] : Math.floor((durations[middle - 1] + durations[middle]) / 2)
+}
