+import { mkdir, readFile, writeFile } from 'node:fs/promises'
+import { dirname } from 'pathe'
+import { smoothDurations, type DurationObservation } from './duration-smoothing'
+
+export type DurationHistory = Record<string, DurationObservation[]>
+
+export async function readDurationHistory(path: string, ttl: number): Promise<DurationHistory | null> {
+  try {
+    const raw = JSON.parse(await readFile(path, 'utf8')) as Record<string, unknown>
+    if (!raw || typeof raw !== 'object' || Array.isArray(raw)) return null
+    const cutoff = ttl > 0 ? Date.now() - ttl : -Infinity
+    const history: DurationHistory = {}
+    for (const [file, entry] of Object.entries(raw)) {
+      const values = typeof entry === 'number'
+        ? [{ duration: entry, recordedAt: 0 }]
+        : entry && typeof entry === 'object' && !Array.isArray(entry)
+          ? 'observations' in entry ? (entry as { observations: unknown }).observations : [entry]
+          : null
+      if (!Array.isArray(values)) return null
+      const observations = values.filter((value): value is DurationObservation => !!value && typeof value === 'object' && Number.isFinite((value as DurationObservation).duration) && Number.isFinite((value as DurationObservation).recordedAt))
+        .filter(value => value.recordedAt === 0 || value.recordedAt >= cutoff)
+      if (observations.length) history[file] = observations
+    }
+    return history
+  }
+  catch {
+    return null
+  }
+}
+
+export function getDuration(history: DurationHistory | null, file: string, smoothing: 'latest' | 'average' | 'p95' | 'median'): number {
